export function script(input) {
  const liveUrls = Array.isArray(input.liveUrls) ? input.liveUrls : [];
  const httpResponses = Array.isArray(input.httpResponses) ? input.httpResponses : [];
  const wafDetections = Array.isArray(input.wafDetections) ? input.wafDetections : [];
  const authorizationNotes = typeof input.authorizationNotes === 'string' && input.authorizationNotes.trim().length > 0 ? input.authorizationNotes.trim() : null;
  const wafByUrl = new Map();
  for (const item of wafDetections) {
    const url = typeof item?.url === 'string' ? item.url : '';
    if (url) wafByUrl.set(url, item);
  }
  const assets = httpResponses.map((resp) => {
    const url = resp?.url || resp?.finalUrl || resp?.input || '';
    const waf = wafByUrl.get(url) || null;
    return {
      url,
      statusCode: resp?.statusCode ?? null,
      title: resp?.title ?? null,
      technologies: Array.isArray(resp?.technologies) ? resp.technologies : [],
      wafDetected: waf?.detected === true,
      firewall: waf?.firewall || null,
      manufacturer: waf?.manufacturer || null
    };
  }).sort((a, b) => Number(b.wafDetected) - Number(a.wafDetected) || Number(b.technologies?.length || 0) - Number(a.technologies?.length || 0));
  const wafBrands = Array.from(new Set(assets.filter((item) => item.wafDetected).map((item) => item.firewall).filter(Boolean)));
  return {
    report: {
      summary: {
        liveUrls: liveUrls.length,
        probedEndpoints: httpResponses.length,
        wafDetections: Number(input.detectionCount || assets.filter((item) => item.wafDetected).length),
        wafBrands,
        interestingWithoutWaf: assets.filter((item) => !item.wafDetected && [200, 401, 403, 500].includes(Number(item.statusCode))).length
      },
      authorizationNotes,
      assets: assets.slice(0, 100),
      nextSteps: [
        'Treat WAF-detected endpoints as edge-protected before active testing',
        'Review 401/403 endpoints without WAF signals for auth bypass opportunities',
        'Stay within authorized scope and rate limits for follow-up testing'
      ]
    }
  };
}
